patterns.codeBlock:
// BEFORE (wrong)
$x = 5
$y = 10;

// AFTER (correct)
$x = 5;
$y = 10;

// Fix autoloading:
composer dump-autoload

// Or verify the namespace matches:
namespace App\Models;
class User { }  // file must be at app/Models/User.php

// BEFORE (wrong)
require 'helpers.php';
require 'helpers.php';  // double include

// AFTER (correct)
require_once 'helpers.php';

// Increase memory at runtime:
ini_set('memory_limit', '512M');

// Better: use generators for large datasets
function readLargeFile($path) {
    $handle = fopen($path, 'r');
    while (($line = fgets($handle)) !== false) {
        yield $line;
    }
    fclose($handle);
}

// Increase time limit for this script:
set_time_limit(300);  // 5 minutes

// Or in php.ini:
// max_execution_time = 300

// BEFORE (wrong)
echo $name;

// AFTER (correct)
$name = $name ?? 'default';
echo $name;

// BEFORE (wrong)
$value = $data['key'];

// AFTER (correct)
$value = $data['key'] ?? null;

// BEFORE (wrong)
function add(int $a, int $b): int { return $a + $b; }
add('5', 3);  // TypeError with strict_types

// AFTER (correct)
add((int)'5', 3);

// Define a named route:
Route::get('/users', [UserController::class, 'index'])->name('{routeName}');

// Clear route cache:
php artisan route:clear

// Add descriptive messages to assertions:
$this->assertEquals(
    $expected,
    $actual,
    'User count should match after import'
);

// BEFORE (wrong)
function getName(): string {
    return null;  // TypeError
}

// AFTER (correct)
function getName(): ?string {
    return null;  // OK with nullable type
}

// Safe JSON decoding with error handling:
$data = json_decode($json, true, 512, JSON_THROW_ON_ERROR);

// Or check manually:
$data = json_decode($json, true);
if (json_last_error() !== JSON_ERROR_NONE) {
    throw new RuntimeException('JSON error: ' . json_last_error_msg());
}
